qry:select.qry:xquery:
for $r in sql(' SELECT PER02_PERSONAL_EMP.e_numero_legajo, PER01_PERSONAL.d_nombres, PER01_PERSONAL.d_apellido, PER01_PERSONAL.d_ape_y_nom, PER01_PERSONAL.c_nro_documento, PER20_TIPOS_DOC.c_tipo_documento, PER20_TIPOS_DOC.d_tipo_documento, PER02_LICEN_PER.f_inicio, PER02_LICEN_PER.f_fin, PER01_PERSONAL.d_email, PER01_PERSONAL.oi_usuario_sistema, ORG03_EMPRESAS.c_empresa, ORG03_EMPRESAS.d_empresa, PER16_LICENCIAS.c_licencia, PER16_LICENCIAS.d_licencia
FROM PER01_PERSONAL, PER02_PERSONAL_EMP, PER20_TIPOS_DOC, PER02_LICEN_PER, PER16_LICENCIAS, ORG03_EMPRESAS
JOIN ORG03_EMPRESAS.oi_empresa INNER PER02_PERSONAL_EMP.oi_empresa, PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal, PER02_PERSONAL_EMP.oi_personal_emp INNER PER02_LICEN_PER.oi_personal_emp, PER02_LICEN_PER.oi_licencia INNER PER16_LICENCIAS.oi_licencia, PER01_PERSONAL.oi_tipo_documento INNER PER20_TIPOS_DOC.oi_tipo_documento
WHERE PER02_PERSONAL_EMP.oi_indic_activo = 1 AND
{%? (#PARAM:@EVENTO='INICIO') {% PER02_LICEN_PER.f_inicio <= {Datetime(#PARAM:@FHASTA)} AND PER02_LICEN_PER.f_inicio >= {Datetime(#PARAM:@FDESDE)} %} {% PER02_LICEN_PER.f_fin <= {Datetime(#PARAM:@FHASTA)} AND PER02_LICEN_PER.f_fin >= {Datetime(#PARAM:@FDESDE)} %} %}
{%? (#PARAM:@TIPOLICENCIA!='') {% AND PER16_LICENCIAS.c_licencia = {#PARAM:@TIPOLICENCIA} %} {% %} %}
{%? (#PARAM:@EMPRESA!='') {% AND ORG03_EMPRESAS.c_empresa = {#PARAM:@EMPRESA} %} {% %} %}
ORDER BY d_empresa ASC, e_numero_legajo ASC, f_fin ASC ')/ROWS/ROW

for $r in sql(' SELECT COUNT(PER02_LICEN_PER.oi_licencia_per) as cantidad
FROM PER01_PERSONAL, PER02_PERSONAL_EMP, PER20_TIPOS_DOC, PER02_LICEN_PER, PER16_LICENCIAS, ORG03_EMPRESAS
JOIN ORG03_EMPRESAS.oi_empresa INNER PER02_PERSONAL_EMP.oi_empresa, PER01_PERSONAL.oi_personal INNER PER02_PERSONAL_EMP.oi_personal, PER02_PERSONAL_EMP.oi_personal_emp INNER PER02_LICEN_PER.oi_personal_emp, PER02_LICEN_PER.oi_licencia INNER PER16_LICENCIAS.oi_licencia, PER01_PERSONAL.oi_tipo_documento INNER PER20_TIPOS_DOC.oi_tipo_documento
WHERE PER02_PERSONAL_EMP.oi_indic_activo = 1 AND
{%? (#PARAM:@EVENTO='INICIO') {% PER02_LICEN_PER.f_inicio <= {Datetime(#PARAM:@FHASTA)} AND PER02_LICEN_PER.f_inicio >= {Datetime(#PARAM:@FDESDE)} %} {% PER02_LICEN_PER.f_fin <= {Datetime(#PARAM:@FHASTA)} AND PER02_LICEN_PER.f_fin >= {Datetime(#PARAM:@FDESDE)} %} %}
{%? (#PARAM:@TIPOLICENCIA!='') {% AND PER16_LICENCIAS.c_licencia = {#PARAM:@TIPOLICENCIA} %} {% %} %}
{%? (#PARAM:@EMPRESA!='') {% AND ORG03_EMPRESAS.c_empresa = {#PARAM:@EMPRESA} %} {% %} %}
')/ROWS/ROW
